import stylesText from './food-log.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import type { FoodLibraryItem } from '@motivation/shared';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';
import {
    HEALTH_EVENTS,
    createSelectLibraryItemEvent,
    createSelectOffItemEvent,
    createLoadMoreOffEvent,
} from '../health-events.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="search-results" id="search-results"></div>
`;

export class FoodSearchResults extends HTMLElement {
    private libraryItemsValue: FoodLibraryItem[] = [];
    private offItemsValue: OFFProduct[] = [];
    private showLoadMoreValue = false;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set libraryItems(value: FoodLibraryItem[]) {
        this.libraryItemsValue = value;
        this.render();
    }

    set offItems(value: OFFProduct[]) {
        this.offItemsValue = value;
        this.render();
    }

    set showLoadMore(value: boolean) {
        this.showLoadMoreValue = value;
        this.render();
    }

    appendOffItems(items: OFFProduct[]): void {
        this.offItemsValue = [...this.offItemsValue, ...items];
        this.render();
    }

    clear(): void {
        this.libraryItemsValue = [];
        this.offItemsValue = [];
        this.showLoadMoreValue = false;
        this.render();
    }

    showEmpty(message: string): void {
        const container = this.shadowRoot!.getElementById('search-results')!;
        container.replaceChildren();
        const empty = document.createElement('p');
        empty.className = 'empty-state';
        empty.textContent = message;
        container.appendChild(empty);
    }

    private render(): void {
        const container = this.shadowRoot!.getElementById('search-results')!;
        container.replaceChildren();

        if (this.libraryItemsValue.length > 0) {
            container.appendChild(this.createSectionLabel('Your Library'));
            for (const item of this.libraryItemsValue) {
                container.appendChild(this.createLibraryRow(item));
            }
        }

        if (this.offItemsValue.length > 0) {
            container.appendChild(this.createSectionLabel('Open Food Facts'));
            for (const item of this.offItemsValue) {
                container.appendChild(this.createOffRow(item));
            }

            if (this.showLoadMoreValue) {
                const btn = document.createElement('button');
                btn.className = 'load-more-btn';
                btn.textContent = 'Load More Results';
                btn.addEventListener('click', () => {
                    btn.disabled = true;
                    btn.textContent = 'Loading…';
                    this.dispatchEvent(createLoadMoreOffEvent());
                });
                container.appendChild(btn);
            }
        }
    }

    private createSectionLabel(text: string): HTMLElement {
        const label = document.createElement('p');
        label.className = 'result-section-label';
        label.textContent = text;
        return label;
    }

    private createLibraryRow(item: FoodLibraryItem): HTMLElement {
        const row = document.createElement('div');
        row.className = 'search-result-item';

        const info = document.createElement('div');
        info.className = 'result-info';

        const name = document.createElement('div');
        name.className = 'result-name';
        name.textContent = item.display_name;

        const brand = document.createElement('div');
        brand.className = 'result-brand';
        brand.textContent = item.brands ?? item.serving_label ?? '';

        const cal = document.createElement('div');
        cal.className = 'result-cal';
        cal.textContent = `${Math.round(item.calories ?? 0)} kcal`;

        info.appendChild(name);
        info.appendChild(brand);
        row.appendChild(info);
        row.appendChild(cal);
        row.addEventListener('click', () => this.dispatchEvent(createSelectLibraryItemEvent(item)));
        return row;
    }

    private createOffRow(item: OFFProduct): HTMLElement {
        const row = document.createElement('div');
        row.className = 'search-result-item';

        if (item.image_url) {
            const img = document.createElement('img');
            img.className = 'result-thumb';
            img.crossOrigin = 'anonymous';
            img.src = item.image_url;
            img.loading = 'lazy';
            row.appendChild(img);
        } else {
            const placeholder = document.createElement('div');
            placeholder.className = 'result-thumb-placeholder';
            row.appendChild(placeholder);
        }

        const info = document.createElement('div');
        info.className = 'result-info';

        const name = document.createElement('div');
        name.className = 'result-name';
        name.textContent = item.product_name;

        const brand = document.createElement('div');
        brand.className = 'result-brand';
        brand.textContent = item.brands ?? '';

        const cal = document.createElement('div');
        cal.className = 'result-cal';
        cal.textContent = `${Math.round(item.calories_per_100g ?? 0)} kcal`;

        info.appendChild(name);
        info.appendChild(brand);
        row.appendChild(info);
        row.appendChild(cal);
        row.addEventListener('click', () => this.dispatchEvent(createSelectOffItemEvent(item)));
        return row;
    }
}

customElements.define('food-search-results', FoodSearchResults);
