import stylesText from './food-log.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { MEAL_TYPES } from '@motivation/shared';
import type { MealType, FoodLibraryItem, NutritionSource } from '@motivation/shared';
import { OpenFoodFactsService } from '../../../services/openfoodfacts.service.js';
import { HealthService } from '../../../services/health.service.js';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';
import {
    HEALTH_EVENTS,
    createScanBarcodeEvent,
    createAiEstimateEvent,
} from '../health-events.js';
import { getDefaultMealType } from '../health-dashboard/health-utils.js';
import './food-search-results.component.js';
import './food-log-detail.component.js';
import type { FoodSearchResults } from './food-search-results.component.js';
import type { FoodLogDetail } from './food-log-detail.component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="food-log-container">
        <div id="search-view">
            <div class="search-bar">
                <input type="text" id="search-input" placeholder="Search for food… (Enter to search online)">
            </div>
            <div class="alt-log-actions" id="alt-log-actions" hidden>
                <button class="alt-log-btn" id="scan-btn">Scan Barcode</button>
                <button class="alt-log-btn" id="ai-btn">AI Estimate</button>
            </div>
            <div id="search-loading" class="loading-text" hidden>Searching…</div>
            <div id="search-error" class="error-text" hidden></div>
            <food-search-results id="search-results-component"></food-search-results>
        </div>

        <div id="detail-view" hidden>
            <food-log-detail id="detail-component"></food-log-detail>
        </div>

        <div id="lookup-loading" class="loading-text" hidden>Looking up product…</div>
    </div>
`;

export interface FoodLogEntry {
    food_name: string;
    serving_size: string;
    meal_type: MealType;
    calories: number;
    protein_g: number;
    carbs_g: number;
    fat_g: number;
    fiber_g: number;
    sugar_g: number;
    sodium_mg: number;
    source: NutritionSource;
    source_ref?: string;
}

export class FoodLog extends HTMLElement {
    private searchTimeout: ReturnType<typeof setTimeout> | null = null;
    private searchSeq = 0;
    private offSearchAbortController: AbortController | null = null;
    private showScanBarcodeActionValue = false;
    private showAiEstimateActionValue = false;
    private defaultMealTypeValue: MealType | null = null;
    private currentQuery = '';
    private currentOffPage = 1;
    private readonly log = createComponentLogger('food-log');

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        const searchInput = shadow.getElementById('search-input') as HTMLInputElement;

        searchInput.addEventListener('input', () => {
            if (this.searchTimeout) clearTimeout(this.searchTimeout);
            this.searchTimeout = setTimeout(() => void this.performLocalSearch(searchInput.value.trim()), 300);
        });

        searchInput.addEventListener('keydown', (e: KeyboardEvent) => {
            if (e.key === 'Enter') {
                if (this.searchTimeout) clearTimeout(this.searchTimeout);
                void this.performSearch(searchInput.value.trim());
            }
        });

        shadow.getElementById('scan-btn')!.addEventListener('click', () => this.dispatchEvent(createScanBarcodeEvent()));
        shadow.getElementById('ai-btn')!.addEventListener('click', () => this.dispatchEvent(createAiEstimateEvent()));

        // Note: SELECT_LIBRARY_ITEM, SELECT_OFF_ITEM, LOAD_MORE_OFF, and FOOD_LOG_BACK
        // bubble past this component to the screen. The screen drives view state via
        // lookupBarcode/lookupLibraryItem/showSearchView/showProduct/showLibraryItem.

        this.applyMealTypeSelection();
        this.updateAltLogActionsVisibility();
    }

    set showScanBarcodeAction(show: boolean) {
        this.showScanBarcodeActionValue = show;
        this.updateAltLogActionsVisibility();
    }

    set showAiEstimateAction(show: boolean) {
        this.showAiEstimateActionValue = show;
        this.updateAltLogActionsVisibility();
    }

    set defaultMealType(mealType: string | null) {
        if (!mealType || !MEAL_TYPES.includes(mealType as MealType)) {
            this.defaultMealTypeValue = null;
        } else {
            this.defaultMealTypeValue = mealType as MealType;
        }
        this.applyMealTypeSelection();
    }

    async lookupBarcode(barcode: string): Promise<void> {
        this.abortOffSearch();
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = true;
        shadow.getElementById('detail-view')!.hidden = true;
        shadow.getElementById('lookup-loading')!.hidden = false;

        const libraryItem = await HealthService.fetchFoodLibraryByBarcode(barcode);
        if (libraryItem) {
            shadow.getElementById('lookup-loading')!.hidden = true;
            this.showLibraryItem(libraryItem);
            return;
        }

        const product = await OpenFoodFactsService.lookupBarcode(barcode);
        shadow.getElementById('lookup-loading')!.hidden = true;

        if (product) {
            this.showProduct(product);
            return;
        }

        shadow.getElementById('search-view')!.hidden = false;
        const errorEl = shadow.getElementById('search-error')!;
        errorEl.textContent = `Product not found for barcode ${barcode}. Try searching by name.`;
        errorEl.hidden = false;
    }

    showProduct(product: OFFProduct): void {
        this.abortOffSearch();
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = true;
        shadow.getElementById('lookup-loading')!.hidden = true;
        shadow.getElementById('detail-view')!.hidden = false;
        const detail = shadow.getElementById('detail-component') as FoodLogDetail;
        detail.showProduct(product);
        this.applyMealTypeSelection();
    }

    async showLibraryItem(item: FoodLibraryItem): Promise<void> {
        this.abortOffSearch();
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = true;
        shadow.getElementById('lookup-loading')!.hidden = true;
        shadow.getElementById('detail-view')!.hidden = false;
        const detail = shadow.getElementById('detail-component') as FoodLogDetail;
        detail.showLibraryItem(item);
        this.applyMealTypeSelection();
    }

    async lookupLibraryItem(id: string): Promise<void> {
        this.abortOffSearch();
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = true;
        shadow.getElementById('detail-view')!.hidden = true;
        shadow.getElementById('lookup-loading')!.hidden = false;

        try {
            const item = await HealthService.fetchFoodLibraryItem(id);
            shadow.getElementById('lookup-loading')!.hidden = true;
            if (item) {
                this.showLibraryItem(item);
            } else {
                this.showSearchView();
            }
        } catch {
            shadow.getElementById('lookup-loading')!.hidden = true;
            this.showSearchView();
        }
    }

    showSearchView(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = false;
        shadow.getElementById('detail-view')!.hidden = true;
        shadow.getElementById('lookup-loading')!.hidden = true;
    }

    private async performLocalSearch(query: string): Promise<void> {
        if (query.length < 2) return;

        const shadow = this.shadowRoot!;
        const results = shadow.getElementById('search-results-component') as FoodSearchResults;
        shadow.getElementById('search-error')!.hidden = true;

        const seq = ++this.searchSeq;
        try {
            const items = await HealthService.fetchFoodLibrarySearch(query);
            if (seq !== this.searchSeq) return;
            results.clear();
            if (items.length > 0) {
                results.libraryItems = items;
            }
        } catch {
            // Local search failure is not critical
        }
    }

    private async performSearch(query: string): Promise<void> {
        if (query.length < 2) return;

        this.currentQuery = query;
        this.currentOffPage = 1;

        const shadow = this.shadowRoot!;
        const results = shadow.getElementById('search-results-component') as FoodSearchResults;
        this.abortOffSearch();
        shadow.getElementById('search-loading')!.hidden = false;
        shadow.getElementById('search-error')!.hidden = true;
        results.clear();

        const seq = ++this.searchSeq;
        this.offSearchAbortController = new AbortController();
        let libraryCount = 0;
        let offCount = 0;
        let libraryDone = false;
        let offDone = false;
        let libraryFailed = false;
        let offFailed = false;

        const finalizeSearch = () => {
            if (seq !== this.searchSeq || !libraryDone || !offDone) return;

            shadow.getElementById('search-loading')!.hidden = true;
            this.offSearchAbortController = null;

            if (libraryFailed && offFailed) {
                const errorEl = shadow.getElementById('search-error')!;
                errorEl.textContent = 'Search failed. Please try again.';
                errorEl.hidden = false;
                return;
            }

            if (libraryCount === 0 && offCount === 0) {
                results.showEmpty('No products found');
            }
        };

        void HealthService.fetchFoodLibrarySearch(query)
            .then((items) => {
                if (seq !== this.searchSeq) return;
                libraryCount = items.length;
                libraryDone = true;
                if (items.length > 0) {
                    results.libraryItems = items;
                }
                finalizeSearch();
            })
            .catch(() => {
                if (seq !== this.searchSeq) return;
                libraryFailed = true;
                libraryDone = true;
                finalizeSearch();
            });

        void OpenFoodFactsService.searchFood(query, {
            signal: this.offSearchAbortController.signal,
            page: 1,
        })
            .then((page) => {
                if (seq !== this.searchSeq) return;
                offCount = page.items.length;
                offDone = true;
                if (page.items.length > 0) {
                    results.offItems = page.items;
                    results.showLoadMore = page.page < page.pageCount;
                }
                finalizeSearch();
            })
            .catch((error) => {
                if (seq !== this.searchSeq) return;
                if (error instanceof Error && error.name === 'AbortError') {
                    return;
                }
                offFailed = true;
                offDone = true;
                finalizeSearch();
            });
    }

    async loadMoreOff(): Promise<void> {
        if (!this.currentQuery) return;
        this.currentOffPage++;

        const shadow = this.shadowRoot!;
        const results = shadow.getElementById('search-results-component') as FoodSearchResults;

        const seq = this.searchSeq;
        this.offSearchAbortController = new AbortController();

        try {
            const page = await OpenFoodFactsService.searchFood(this.currentQuery, {
                signal: this.offSearchAbortController.signal,
                page: this.currentOffPage,
            });

            if (seq !== this.searchSeq) return;

            if (page.items.length > 0) {
                results.appendOffItems(page.items);
                results.showLoadMore = page.page < page.pageCount;
            } else {
                results.showLoadMore = false;
            }
        } catch (error) {
            if (error instanceof Error && error.name === 'AbortError') return;
            this.log.error('Failed to load more OFF results', error);
            results.showLoadMore = false;
        } finally {
            this.offSearchAbortController = null;
        }
    }

    private abortOffSearch(): void {
        this.offSearchAbortController?.abort();
        this.offSearchAbortController = null;
    }

    private applyMealTypeSelection(): void {
        const detail = this.shadowRoot?.getElementById('detail-component') as FoodLogDetail | null;
        if (detail) {
            const mealType = this.defaultMealTypeValue ?? getDefaultMealType();
            detail.defaultMealType = mealType;
            const mealSelect = detail.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null;
            if (mealSelect) {
                mealSelect.value = mealType;
            }
        }
    }

    private updateAltLogActionsVisibility(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const actionsEl = shadow.getElementById('alt-log-actions');
        if (!actionsEl) return;
        const hasAltActions = this.showScanBarcodeActionValue || this.showAiEstimateActionValue;
        actionsEl.hidden = !hasAltActions;

        const scanButton = shadow.getElementById('scan-btn') as HTMLButtonElement | null;
        if (scanButton) scanButton.hidden = !this.showScanBarcodeActionValue;

        const aiButton = shadow.getElementById('ai-btn') as HTMLButtonElement | null;
        if (aiButton) aiButton.hidden = !this.showAiEstimateActionValue;
    }
}

customElements.define('food-log', FoodLog);
